import { useEffect, useMemo, useState } from "react";
import api from "../../api/axios";
import { useNavigate } from "react-router-dom";

export default function LeadList() {
  const [leads, setLeads] = useState([]);
  const [loading, setLoading] = useState(false);
  const [statusFilter, setStatusFilter] = useState("all");
  const navigate = useNavigate();

  const load = async () => {
    setLoading(true);
    try {
      const res = await api.get("/leads");
      setLeads(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load leads");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const stats = useMemo(() => {
    const total = leads.length;
    const hot = leads.filter((l) => l.interest_level === "high").length;
    const contacted = leads.filter((l) => l.status === "contacted").length;
    const converted = leads.filter((l) => l.status === "converted").length;
    return { total, hot, contacted, converted };
  }, [leads]);

  const filtered = useMemo(() => {
    if (statusFilter === "all") return leads;
    return leads.filter((l) => l.status === statusFilter);
  }, [leads, statusFilter]);

  const onDelete = async (id, name) => {
    if (!window.confirm(`Delete lead "${name}"?`)) return;

    try {
      await api.delete(`/leads/${id}`);
      setLeads((prev) => prev.filter((l) => l._id !== id));
      alert("Lead deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const getStatusBadge = (status) => {
    const statusMap = {
      new: "badgeInfo",
      contacted: "badgeWarning",
      qualified: "badgeSuccess",
      converted: "badgeSuccess",
      lost: "badgeDanger",
    };
    return statusMap[status] || "badge";
  };

  const getInterestBadge = (level) => {
    const interestMap = {
      high: "badgeSuccess",
      medium: "badgeWarning",
      low: "badgeInfo",
    };
    return interestMap[level] || "badge";
  };

  return (
    <div className="page">
      {/* Page Header */}
      <div className="pageHead">
        <div>
          <div className="pageTitle">Lead Management</div>
          <div className="pageSub">Track and manage all customer leads and prospects</div>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="kpiGrid">
        <div className="kpiCard">
          <div className="kpiLabel">Total Leads</div>
          <div className="kpiValue">{loading ? "—" : stats.total}</div>
          <div className="kpiSub">Active prospects</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Hot Leads</div>
          <div className="kpiValue">{loading ? "—" : stats.hot}</div>
          <div className="kpiSub">High interest</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Contacted</div>
          <div className="kpiValue">{loading ? "—" : stats.contacted}</div>
          <div className="kpiSub">In progress</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Converted</div>
          <div className="kpiValue">{loading ? "—" : stats.converted}</div>
          <div className="kpiSub">Successful sales</div>
        </div>
      </div>

      {/* Filter & Actions Card */}
      <div className="card cardPad" style={{ marginBottom: 14 }}>
        <div className="row" style={{ alignItems: "center", flexWrap: "wrap" }}>
          <div>
            <div className="sectionTitle">Lead Management</div>
            <div className="sub">Filter and manage your customer leads</div>
          </div>

          <div style={{ display: "flex", gap: 10, alignItems: "center", marginLeft: "auto", flexWrap: "wrap" }}>
            <select
              className="select"
              style={{ minWidth: 180 }}
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
            >
              <option value="all">All Status</option>
              <option value="new">New</option>
              <option value="contacted">Contacted</option>
              <option value="converted">Converted</option>
              <option value="lost">Lost</option>
            </select>

            <button className="btn btnPrimary" onClick={() => navigate("/leads/add")}>
              ➕ Add Lead
            </button>
            <button 
              className="btn" 
              onClick={load} 
              disabled={loading}
              style={{ minWidth: 100 }}
            >
              {loading ? "Loading..." : "Refresh"}
            </button>
          </div>
        </div>
      </div>

      {/* Leads Table */}
      <div className="card cardPad">
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ borderBottom: "2px solid var(--border-light)" }}>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Name</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Contact</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Email</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Source</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Interest</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Status</th>
              <th style={{ padding: "12px", textAlign: "right", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map((lead) => (
              <tr key={lead._id} style={{ borderBottom: "1px solid var(--border-light)", transition: "background 0.2s" }}>
                <td style={{ padding: "12px", fontWeight: "500", color: "var(--text)" }}>{lead.name}</td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>{lead.contact_number}</td>
                <td style={{ padding: "12px", color: "var(--text-secondary)", fontSize: "13px" }}>{lead.email}</td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>{lead.lead_source || "—"}</td>
                <td style={{ padding: "12px" }}>
                  <span className={`badge ${getInterestBadge(lead.interest_level)}`}>
                    {lead.interest_level || "—"}
                  </span>
                </td>
                <td style={{ padding: "12px" }}>
                  <span className={`badge ${getStatusBadge(lead.status)}`}>
                    {lead.status || "—"}
                  </span>
                </td>
                <td style={{ padding: "12px", textAlign: "right" }}>
                  <button 
                    className="btn btnSmall" 
                    onClick={() => navigate(`/leads/edit/${lead._id}`)}
                    style={{ marginRight: 6 }}
                  >
                    ✏️ Edit
                  </button>
                  <button
                    className="btn btnSmall"
                    onClick={() => onDelete(lead._id, lead.name)}
                    style={{ background: "var(--danger)", color: "white" }}
                  >
                    🗑️ Delete
                  </button>
                </td>
              </tr>
            ))}

            {filtered.length === 0 && !loading && (
              <tr>
                <td colSpan="7" style={{ padding: "40px", textAlign: "center", color: "var(--text-secondary)" }}>
                  {statusFilter !== "all" ? "No leads found with this status" : "No leads yet. Start by adding your first lead"}
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
